  <script>
    document.addEventListener('DOMContentLoaded', function() {
      const statusElement = document.querySelector('status');
      const statusText = statusElement.textContent.trim();

      // 解析状态信息
      const lines = statusText.split('\n').map(line => line.trim()).filter(line => line);

      // 清空原有内容
      statusElement.innerHTML = '';

      // 更多emoji
      const emojis = ['🐧', '❤', '🔞', '👚', '🩳', '🩲', '🩴', '🏙', '📅', '🕗', '📍', '💭', '🍰', '🤢', '👥', '👩‍🎨', '💉', '📏', '⚖️', '♌'];

      // 处理每行数据并添加动画延迟
      lines.forEach((line, index) => {
        const separatorIndex = line.indexOf('：');
        if (separatorIndex !== -1) {
          const label = line.substring(0, separatorIndex);
          const value = line.substring(separatorIndex + 1);

          const statusItem = document.createElement('div');
          statusItem.className = `status-item bg-${index % 20}`;
          statusItem.style.animationDelay = `${index * 0.1}s`;

          const labelSpan = document.createElement('span');
          labelSpan.className = 'label';
          labelSpan.innerHTML = `<span style="flex-shrink:0;">${emojis[index % emojis.length]}</span> <span style="overflow:hidden;text-overflow:ellipsis;">${label}</span>`;

          const valueSpan = document.createElement('span');
          valueSpan.className = `value color-${index % 20}`;
          valueSpan.textContent = value;
          valueSpan.title = value; // 添加title属性以便鼠标悬停时显示完整内容

          statusItem.appendChild(labelSpan);
          statusItem.appendChild(valueSpan);

          statusElement.appendChild(statusItem);
        }
      });

      // 添加切换按钮功能
      const toggleButton = document.getElementById('toggleButton');
      const cardContent = document.getElementById('cardContent');
      const poweredContent = document.getElementById('poweredContent');
      const card = document.getElementById('card');

      let isHidden = false;

      toggleButton.addEventListener('click', function() {
        isHidden = !isHidden;

        if (isHidden) {
          // 隐藏状态信息，显示Powered By
          cardContent.classList.add('hidden');
          setTimeout(() => {
            cardContent.style.display = 'none';
            poweredContent.classList.add('show');
            poweredContent.style.display = 'block';
            // 调整卡片padding以适应内容
            card.style.padding = 'clamp(30px, 7vw, 45px) clamp(25px, 6vw, 35px)';
          }, 300);
          toggleButton.textContent = '显示';
        } else {
          // 显示状态信息，隐藏Powered By
          poweredContent.classList.remove('show');
          setTimeout(() => {
            poweredContent.style.display = 'none';
            cardContent.style.display = 'block';
            cardContent.classList.remove('hidden');
            // 恢复卡片padding
            card.style.padding = 'clamp(20px, 5vw, 28px)';
            toggleButton.textContent = '隐藏';
          }, 300);
        }
      });
    });
  </script>
</body>
