<script>
document.addEventListener('DOMContentLoaded', function() {

    function initPostItCard() {
        const elements = {
            card: document.getElementById('post-it-card'),
            collapsibleContent: document.getElementById('collapsible-content'),
            optionsContainer: document.getElementById('options-container'),
            rawData: document.getElementById('raw-options-data')
        };

        if (!elements.card || !elements.rawData || !elements.optionsContainer) {
            console.error("Post-it card essential elements not found.");
            return;
        }

        setupOptionList(elements.rawData, elements.optionsContainer);
        setupCollapsible(elements);
    }

    function setupOptionList(dataEl, targetContainer) {
        const rawText = dataEl.textContent.trim();
        const lines = rawText.split(/\r?\n/).filter(line => line.trim() !== '');

        lines.forEach(line => {
            const cleanText = line.trim().replace(/^[A-Z]\.\s*/i, '');
            if (!cleanText) return;

            const optionDiv = document.createElement('div');
            optionDiv.className = 'clickable-text';
            optionDiv.setAttribute('data-action', cleanText);
            optionDiv.innerHTML = `<li>${cleanText}</li>`;

            optionDiv.addEventListener('click', function() {
                const textToSend = this.getAttribute('data-action');
                try {
                    const input = window.parent.document.querySelector('#send_textarea');
                    const trigger = window.parent.triggerSlash;
                    if (input) {
                        const newValue = input.value + textToSend;
                        if (trigger) {
                            trigger(`/setinput ${newValue}`);
                        } else {
                            input.value = newValue;
                            input.dispatchEvent(new Event('input', { bubbles: true }));
                        }
                    } else if (trigger) {
                        trigger(`/setinput ${textToSend}`);
                    }
                } catch (e) {
                    console.error('Error setting input text:', e);
                }
            });
            targetContainer.appendChild(optionDiv);
        });
    }

    function setupCollapsible(elements) {
        const { card, collapsibleContent, optionsContainer } = elements;

        card.addEventListener('click', (event) => {
            const interactiveElements = [
                ...optionsContainer.querySelectorAll('.clickable-text')
            ];

            const isClickOnInteractiveChild = interactiveElements.some(el => el && el.contains(event.target));

            if (!isClickOnInteractiveChild) {
                collapsibleContent.classList.toggle('open');
            }
        });
    }

    initPostItCard();
});
</script>
</body>
</html>
