document.addEventListener('DOMContentLoaded', () => {
 /*=== 核心功能：直接窃取并同步酒馆的主题颜色与字体 ===*/
 try {
 const pDoc = window.parent.document;
 const mesText = pDoc.querySelector('.mes_text') || pDoc.body;
 const syncStyle = () => {
 const st = window.parent.getComputedStyle(mesText);
 document.body.style.color = st.color; // 同步文字颜色
 document.body.style.fontFamily = st.fontFamily; // 同步自定义字体
 };
 syncStyle(); // 立即同步一次

 // 设立监控：当你在酒馆设置里更改主题时，它立刻跟着变
 const obs = new MutationObserver(syncStyle);
 obs.observe(pDoc.body, { attributes: true, attributeFilter: ['data-theme', 'style', 'class'] });
 } catch(e){ console.warn("Theme sync failed", e); }

 /*=== 原版的按钮与折叠逻辑 ===*/
 const t = document.getElementById('t'), b = document.getElementById('b'), s = document.getElementById('s'), d = document.getElementById('d'), o = document.getElementById('o');
 let isOpen = false;
 t.onclick = () => {
 isOpen = !isOpen;
 s.textContent = isOpen ? 'OPEN' : 'CLOSED';
 if (isOpen) {
 t.classList.add('open');
 b.classList.add('show');
 setTimeout(() => b.classList.add('fade-in'), 10);
 } else {
 t.classList.remove('open');
 b.classList.remove('fade-in');
 setTimeout(() => b.classList.remove('show'), 150);
 }
 };
 if (d && o) {
 d.textContent.trim().split(/\r?\n/).filter(l => l.trim()).forEach(l => {
 const txt = l.trim().replace(/^[A-Z]\.\s*/i, '');
 if (!txt) return;
 const i = document.createElement('div'); i.className = 'opt'; i.innerHTML = `<span>${txt}</span>`;
 i.onclick = (e) => {
 e.stopPropagation();
 const inp = window.parent.document.querySelector('#send_textarea'), tr = window.parent.triggerSlash;
 if (inp) {
 inp.value += txt;
 inp.dispatchEvent(new Event('input', { bubbles: true }));
 inp.focus(); // 自动聚焦输入框
 } else if (tr) tr(`/setinput ${txt}`);
 };
 o.appendChild(i);
 });
 }
});
</script>
